#include<bits/stdc++.h>
using namespace std;

int a[1000006];

int main()
{
    int n, m;
    cin >> n >> m;
    for(int i = 1; i <= n; i++)
        cin >> a[i];
    for(int i = 1; i <= m; i++)
    {
        int x;
        cin >> x;
        int p = lower_bound(a + 1, a + n + 1, x) - a;
        if(a[p] != x) cout << -1 << ' ';
        else cout << p << ' ';
    }
}
